import { describe, expect, it } from 'vitest';

import {
  adist,
  admitCoincidence,
  consistent,
  countConsistent,
  CrossNodeCoincidenceMaster,
  hyp,
  nodeA,
  nodeB,
  nodeC,
  predictedArrival,
  realNodes,
  residual,
  spoofer,
  type MeshNode,
} from '../src/cross-node-coincidence';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(10, 4)).toBe(6);
    expect(adist(4, 10)).toBe(6);
    expect(adist(0, 20)).toBe(20);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('predictedArrival (mirrors predicted_at_source / vantages_distinct)', () => {
  it('at the source position the arrival is the emission time', () => {
    expect(predictedArrival(hyp, hyp.position)).toBe(hyp.emissionTime);
  });

  it('adds the corridor distance to the emission time', () => {
    expect(predictedArrival(hyp, 0)).toBe(104);
    expect(predictedArrival(hyp, 4)).toBe(100);
    expect(predictedArrival(hyp, 10)).toBe(106);
  });

  it('distinct vantages give distinct arrivals (104 != 106)', () => {
    expect(predictedArrival(hyp, 0)).not.toBe(predictedArrival(hyp, 10));
  });

  it('residual is the gap between report and predicted arrival', () => {
    expect(residual(hyp, nodeA)).toBe(0);
    expect(residual(hyp, nodeB)).toBe(0);
    expect(residual(hyp, nodeC)).toBe(0);
    // spoofer reports 100 but geometry predicts 116 => residual 16
    expect(residual(hyp, spoofer)).toBe(16);
  });
});

describe('consistency and counting (mirrors consistentB / countConsistent)', () => {
  it('an honest in-tolerance detecting ear is consistent', () => {
    expect(consistent(1, hyp, nodeA)).toBe(true);
    expect(consistent(1, hyp, nodeB)).toBe(true);
    expect(consistent(1, hyp, nodeC)).toBe(true);
  });

  it('an undetected ear is never consistent even at exact arrival', () => {
    const silent: MeshNode = { ...nodeA, detected: false };
    expect(consistent(1, hyp, silent)).toBe(false);
  });

  it('counts the mutually-consistent ears', () => {
    expect(countConsistent(1, hyp, realNodes)).toBe(3);
    expect(countConsistent(1, hyp, [nodeA])).toBe(1);
    expect(countConsistent(1, hyp, [spoofer])).toBe(0);
  });
});

describe('promotion check: admitCoincidence', () => {
  it('admits when a quorum K>=2 of independent ears agree', () => {
    // mirrors real_event_admitted (K=2) and real_event_full_quorum (K=3)
    const two = admitCoincidence(realNodes, hyp, 2, 1);
    expect(two.outcome).toBe('claim_admitted');
    expect(two.quorumMet).toBe(true);
    expect(two.coincidenceCount).toBe(3);
    expect(two.consistentNodes).toEqual([0, 1, 2]);

    const three = admitCoincidence(realNodes, hyp, 3, 1);
    expect(three.outcome).toBe('claim_admitted');
    expect(three.quorumMet).toBe(true);
  });

  it('downgrades to observation_only when consistent ears are below quorum', () => {
    // one honest ear is consistent but the quorum of two is not reached.
    const a = admitCoincidence([nodeA], hyp, 2, 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.coincidenceCount).toBe(1);
    expect(a.consistentNodes).toEqual([0]);
  });

  it('refuses to admit at K<2 even when an ear is consistent (single-ear cannot self-certify)', () => {
    // mirrors single_ear_not_admitted: a lone ear can never reach a quorum.
    const a = admitCoincidence(realNodes, hyp, 1, 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.summary).toContain('< 2');
  });

  it('withholds when no ear is consistent with the hypothesis', () => {
    const a = admitCoincidence([spoofer], hyp, 2, 1);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.quorumMet).toBe(false);
    expect(a.coincidenceCount).toBe(0);
    expect(a.consistentNodes).toEqual([]);
  });
});

describe('spoofer rejection + non-inflation (mirrors spoofer_rejected / spoofer_does_not_inflate)', () => {
  it('the geometrically-inconsistent spoofer is rejected', () => {
    expect(consistent(1, hyp, spoofer)).toBe(false);
  });

  it('the spoofer cannot inflate the coincidence count', () => {
    expect(countConsistent(1, hyp, [...realNodes, spoofer])).toBe(
      countConsistent(1, hyp, realNodes),
    );
  });

  it('the spoofer does not appear among the admitted nodes', () => {
    const a = admitCoincidence([...realNodes, spoofer], hyp, 2, 1);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.coincidenceCount).toBe(3);
    // index 3 (the spoofer) is excluded
    expect(a.consistentNodes).toEqual([0, 1, 2]);
  });
});

describe('CrossNodeCoincidenceMaster (mirrors mesh_coincidence_master)', () => {
  it('every boundary witness holds', () => {
    expect(CrossNodeCoincidenceMaster.realEventAdmittedAtTwo).toBe(true);
    expect(CrossNodeCoincidenceMaster.realEventAdmittedAtThree).toBe(true);
    expect(CrossNodeCoincidenceMaster.loneEarNotAdmitted).toBe(true);
    expect(CrossNodeCoincidenceMaster.spooferRejected).toBe(true);
    expect(CrossNodeCoincidenceMaster.spooferDoesNotInflate).toBe(true);
    expect(CrossNodeCoincidenceMaster.fixtureVantagesDistinct).toBe(true);
  });
});
